use std::{
    fs,
    path::{Path, PathBuf},
    time::Instant,
};

use dust_cache::WorkspaceCache;
use dust_diagnostics::Diagnostic;
use dust_workspace::{detect_workspace_root, load_dust_config};

use crate::{CleanReport, CleanRequest, CommandResult};

/// Start marker required before Dust will delete a generated file.
const DUST_HEADER_START: &str = "// GENERATED CODE - DO NOT MODIFY BY HAND";
/// Header line required near the top of generated Dust-owned files.
const DUST_HEADER_END: &str = "// Generated by dust.";

/// Removes Dust-generated outputs plus `.dart_tool/dust` cache state.
pub fn run_clean(request: CleanRequest) -> CommandResult {
    let started = Instant::now();
    let mut result = CommandResult::default();

    let package_root = match detect_workspace_root(&request.cwd) {
        Ok(root) => root,
        Err(diagnostic) => {
            result.diagnostics.push(diagnostic);
            result.elapsed_ms = started.elapsed().as_millis();
            return result;
        }
    };
    let dust_config = match load_dust_config(&package_root) {
        Ok(config) => config,
        Err(diagnostic) => {
            result.diagnostics.push(diagnostic);
            result.elapsed_ms = started.elapsed().as_millis();
            return result;
        }
    };

    let mut generated_files = Vec::new();
    if let Err(diagnostic) =
        collect_generated_files(&package_root.join("lib"), &mut generated_files, &|path| {
            matches_suffix(path, &dust_config.outputs.primary_suffix)
        })
    {
        result.diagnostics.push(diagnostic);
        result.elapsed_ms = started.elapsed().as_millis();
        return result;
    }
    if let Err(diagnostic) = collect_generated_files(
        &package_root.join("test/generated"),
        &mut generated_files,
        &is_generated_test_file,
    ) {
        result.diagnostics.push(diagnostic);
        result.elapsed_ms = started.elapsed().as_millis();
        return result;
    }

    let scanned_files = generated_files.len();
    let mut removed_files = 0usize;

    for output_path in generated_files {
        match is_dust_generated_file(&output_path) {
            Ok(true) => match fs::remove_file(&output_path) {
                Ok(()) => removed_files += 1,
                Err(error) => result.diagnostics.push(Diagnostic::error(format!(
                    "failed to remove Dust output `{}`: {error}",
                    output_path.display()
                ))),
            },
            Ok(false) => {}
            Err(error) => result.diagnostics.push(Diagnostic::error(format!(
                "failed to inspect generated file `{}`: {error}",
                output_path.display()
            ))),
        }
    }

    let cache_cleared = if result.has_errors() {
        false
    } else {
        match WorkspaceCache::delete_storage(&package_root) {
            Ok(cache_cleared) => cache_cleared,
            Err(error) => {
                result.diagnostics.push(Diagnostic::error(format!(
                    "failed to remove Dust cache storage under `{}`: {error}",
                    package_root.join(".dart_tool/dust").display()
                )));
                false
            }
        }
    };

    result.clean = Some(CleanReport {
        package_root,
        scanned_files,
        removed_files,
        cache_cleared,
    });
    result.elapsed_ms = started.elapsed().as_millis();
    result
}

/// Recursively collects generated files under a directory in sorted order.
fn collect_generated_files(
    dir: &Path,
    out: &mut Vec<PathBuf>,
    matcher: &dyn Fn(&Path) -> bool,
) -> Result<(), Diagnostic> {
    if !dir.is_dir() {
        return Ok(());
    }

    let mut entries = fs::read_dir(dir)
        .map_err(|error| {
            Diagnostic::error(format!(
                "failed to read directory `{}`: {error}",
                dir.display()
            ))
        })?
        .collect::<Result<Vec<_>, _>>()
        .map_err(|error| {
            Diagnostic::error(format!(
                "failed to enumerate directory `{}`: {error}",
                dir.display()
            ))
        })?;
    entries.sort_by_key(|entry| entry.path());

    for entry in entries {
        let path = entry.path();
        if path.is_dir() {
            collect_generated_files(&path, out, matcher)?;
        } else if matcher(&path) {
            out.push(path);
        }
    }

    Ok(())
}

/// Returns whether a path's file name ends with the configured suffix.
fn matches_suffix(path: &Path, suffix: &str) -> bool {
    path.file_name()
        .and_then(|name| name.to_str())
        .is_some_and(|name| name.ends_with(suffix))
}

/// Returns whether a path looks like a generated test file.
fn is_generated_test_file(path: &Path) -> bool {
    matches_suffix(path, "_test.dart")
}

/// Checks the generated header markers before allowing deletion.
fn is_dust_generated_file(path: &Path) -> Result<bool, std::io::Error> {
    let contents = fs::read_to_string(path)?;
    let has_header = contents.starts_with(DUST_HEADER_START);
    let has_footer = contents
        .lines()
        .take(20)
        .any(|line| line.starts_with(DUST_HEADER_END));
    Ok(has_header && has_footer)
}

#[cfg(test)]
mod tests {
    #[cfg(unix)]
    use std::os::unix::fs::PermissionsExt;

    use dust_plugin_api::GENERATED_HEADER;
    use tempfile::tempdir;

    use super::*;

    fn dust_generated_output(body: &str) -> String {
        format!("{GENERATED_HEADER}\n{body}")
    }

    #[test]
    fn dust_generated_file_requires_exact_header_prefix() {
        let temp = tempdir().unwrap();
        let owned = temp.path().join("owned.g.dart");
        let foreign = temp.path().join("foreign.g.dart");

        fs::write(&owned, dust_generated_output("part of 'x.dart';\n")).unwrap();
        fs::write(&foreign, "part of 'x.dart';\n// Generated by dust.\n").unwrap();

        assert!(is_dust_generated_file(&owned).unwrap());
        assert!(!is_dust_generated_file(&foreign).unwrap());
    }

    #[test]
    fn dust_generated_file_accepts_variants_within_master_header() {
        let temp = tempdir().unwrap();
        let owned = temp.path().join("owned_test.dart");

        fs::write(&owned, dust_generated_output("import 'x.dart';\n")).unwrap();

        assert!(is_dust_generated_file(&owned).unwrap());
    }

    #[test]
    fn collect_generated_files_only_returns_matching_files_in_sorted_order() {
        let temp = tempdir().unwrap();
        let lib_dir = temp.path().join("lib");
        let nested = lib_dir.join("nested");
        fs::create_dir_all(&nested).unwrap();
        fs::write(lib_dir.join("a.g.dart"), "").unwrap();
        fs::write(lib_dir.join("b.dart"), "").unwrap();
        fs::write(nested.join("c.g.dart"), "").unwrap();

        let mut files = Vec::new();
        collect_generated_files(&lib_dir, &mut files, &|path| {
            matches_suffix(path, ".g.dart")
        })
        .unwrap();

        assert_eq!(files.len(), 2);
        assert!(files[0].ends_with("a.g.dart"));
        assert!(files[1].ends_with("c.g.dart"));
    }

    #[test]
    fn clean_skips_cache_deletion_when_output_removal_fails() {
        let temp = tempdir().unwrap();
        let root = temp.path();
        let lib_dir = root.join("lib");
        let dart_tool_dir = root.join(".dart_tool/dust");
        fs::create_dir_all(&lib_dir).unwrap();
        fs::create_dir_all(&dart_tool_dir).unwrap();
        fs::write(root.join("pubspec.yaml"), "name: sample\n").unwrap();
        fs::write(
            root.join(".dart_tool/package_config.json"),
            r#"{"configVersion":2,"packages":[]}"#,
        )
        .unwrap();
        let owned = lib_dir.join("user.g.dart");
        fs::write(&owned, dust_generated_output("")).unwrap();

        make_dir_readonly(&lib_dir);

        let result = run_clean(CleanRequest {
            cwd: root.to_path_buf(),
        });

        make_dir_writable(&lib_dir);

        assert!(result.has_errors());
        assert!(owned.exists());
        assert!(dart_tool_dir.exists());
        assert!(!result.clean.unwrap().cache_cleared);
    }

    #[cfg(unix)]
    fn make_dir_readonly(path: &Path) {
        let mut perms = fs::metadata(path).unwrap().permissions();
        perms.set_mode(0o555);
        fs::set_permissions(path, perms).unwrap();
    }

    #[cfg(unix)]
    fn make_dir_writable(path: &Path) {
        let mut perms = fs::metadata(path).unwrap().permissions();
        perms.set_mode(0o755);
        fs::set_permissions(path, perms).unwrap();
    }

    #[cfg(windows)]
    fn make_dir_readonly(path: &Path) {
        let mut perms = fs::metadata(path).unwrap().permissions();
        perms.set_readonly(true);
        fs::set_permissions(path, perms).unwrap();
    }

    #[cfg(windows)]
    fn make_dir_writable(path: &Path) {
        let mut perms = fs::metadata(path).unwrap().permissions();
        perms.set_readonly(false);
        fs::set_permissions(path, perms).unwrap();
    }
}
